#include <bits/stdc++.h>
using namespace std;
const int N=102;
int n,m,v[N],w[N],s[N],dp[N][40004];
int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
        scanf("%d%d%d",&v[i],&w[i],&s[i]);
    for(int i=1;i<=n;i++)
        for(int j=1;j<=m;j++)
            for(int k=0;k<=s[i] && k*w[i]<=j;k++)
                dp[i][j]=max(dp[i][j],dp[i-1][j-k*w[i]]+k*v[i]);
    printf("%d",dp[n][m]);
    return 0;
}
